examples.solution:
def get_pomdp_components():
    """Return a dict mapping each POMDP component letter to a one-line description."""
    components = {
        "A": "observation model — maps hidden states to observations",
        "B": "transition model — describes how hidden states change over time",
        "C": "preferences — the agent's preferred observations or outcomes",
        "D": "initial state prior — the agent's belief about where it starts"
    }
    return components

tests.code:
result = get_pomdp_components()
for key in ['A', 'B', 'C', 'D']:
    assert isinstance(result[key], str) and len(result[key]) > 0, f'Value for "{key}" must be a non-empty string'
